package ir.matin.biology11.data

object Chapter9Essay {
    val questions = listOf(
        EssayQuestion("تنه‌جنبی (تروپیسم) را تعریف کرده و انواع مثبت و منفی آن را توضیح دهید.", "تنه‌جنبی پاسخ جهت‌دار گیاه به یک محرک محیطی از طریق تغییر جهت رشد است. تنه‌جنبی مثبت یعنی رشد به سمت محرک (مانند رشد ساقه به سمت نور) و تنه‌جنبی منفی یعنی رشد در خلاف جهت محرک (مانند رشد ساقه در خلاف جهت گرانش)."),
        EssayQuestion("مکانیسم نورگرایی مثبت ساقه را توضیح دهید.", "وقتی نور از یک سمت به ساقه می‌تابد، هورمون اکسین در سمت تاریک‌تر ساقه تجمع بیشتری می‌یابد. اکسین باعث طویل شدن سریع‌تر یاخته‌های همان سمت می‌شود؛ در نتیجه ساقه به سمت منبع نور خم می‌شود."),
        EssayQuestion("تفاوت گرانش‌گرایی ریشه و ساقه را بنویسید.", "ریشه‌ها معمولاً گرانش‌گرایی مثبت دارند و به سمت پایین (جهت نیروی گرانش) رشد می‌کنند تا در خاک نفوذ کنند. ساقه‌ها معمولاً گرانش‌گرایی منفی دارند و به سمت بالا رشد می‌کنند تا به نور دسترسی بیشتری داشته باشند."),
        EssayQuestion("لمس‌گرایی (تیگموتروپیسم) چیست و در کدام گیاهان بیشتر دیده می‌شود؟", "لمس‌گرایی پاسخ رشدی گیاه به تماس فیزیکی با یک سطح جامد است. در گیاهان بالارونده و پیچک‌دار مانند انگور و لوبیا بیشتر دیده می‌شود که پیچک یا ساقه خود را دور تکیه‌گاه می‌پیچانند."),
        EssayQuestion("اکسین کجا ساخته می‌شود و چه اثراتی دارد؟", "اکسین عمدتاً در نوک ساقه و جوانه‌های انتهایی ساخته می‌شود. اثرات آن شامل طویل شدن یاخته‌ها، نورگرایی، گرانش‌گرایی، تحریک ریشه‌زایی در قلمه‌ها و ایجاد برتری انتهایی (مهار رشد جوانه‌های جانبی) است."),
        EssayQuestion("برتری انتهایی چیست و با کدام هورمون مرتبط است؟", "برتری انتهایی پدیده‌ای است که در آن جوانه انتهایی ساقه با ترشح اکسین، رشد جوانه‌های جانبی زیر خود را مهار می‌کند؛ حذف جوانه انتهایی (هرس سرشاخه) باعث آزاد شدن جوانه‌های جانبی و رشد بیشتر شاخه‌های فرعی می‌شود."),
        EssayQuestion("جیبرلین چه اثراتی بر رشد گیاه دارد؟", "جیبرلین باعث طویل شدن ساقه (به‌ویژه در گیاهان کوتوله)، شکستن خواب دانه و جوانه، و تحریک جوانه‌زنی دانه از طریق فعال کردن آنزیم‌های تجزیه‌کننده نشاسته ذخیره‌ای دانه می‌شود."),
        EssayQuestion("سیتوکینین کجا ساخته می‌شود و چه اثراتی دارد؟", "سیتوکینین عمدتاً در ریشه ساخته شده و به ساقه منتقل می‌شود. باعث تحریک تقسیم یاخته‌ای، تأخیر در پیری برگ‌ها و تحریک رشد جوانه‌های جانبی می‌شود."),
        EssayQuestion("نسبت اکسین به سیتوکینین چه اهمیتی در کشت بافت گیاهی دارد؟", "نسبت این دو هورمون در محیط کشت بافت، تعیین می‌کند که یاخته‌های گیاهی به سمت تشکیل ریشه یا ساقه تمایز پیدا کنند؛ نسبت‌های متفاوت اکسین به سیتوکینین می‌تواند رشد اندام‌های مختلف را در آزمایشگاه هدایت کند."),
        EssayQuestion("چرا اتیلن را هورمون گیاهی خاص می‌دانند؟", "اتیلن تنها هورمون گیاهی است که به‌صورت گاز تولید و منتقل می‌شود؛ این ویژگی باعث می‌شود اثر آن می‌تواند به یاخته‌های مجاور و حتی میوه‌های اطراف نیز به‌راحتی منتقل شود."),
        EssayQuestion("چرا قرار دادن یک میوه رسیده در کنار میوه‌های نارس، رسیدن آنها را تسریع می‌کند؟", "میوه رسیده مقدار زیادی اتیلن گازی تولید می‌کند که به میوه‌های نارس اطراف نیز پخش شده و فرایند رسیدن (نرم شدن بافت، تغییر رنگ و افزایش قند) را در آنها نیز تحریک می‌کند."),
        EssayQuestion("آبسیزیک اسید (ABA) در چه شرایطی تولید می‌شود و چه اثری دارد؟", "ABA در شرایط تنش محیطی مانند کم‌آبی تولید می‌شود و با بسته کردن روزنه‌های برگ، تبخیر و از دست رفتن آب گیاه را کاهش می‌دهد؛ همچنین در القا و حفظ خواب دانه نقش دارد."),
        EssayQuestion("تعادل بین کدام دو هورمون، زمان جوانه‌زنی دانه را تعیین می‌کند؟", "تعادل بین آبسیزیک اسید (بازدارنده و حافظ خواب دانه) و جیبرلین (شکننده خواب دانه و محرک جوانه‌زنی) تعیین می‌کند که دانه در چه زمان و شرایطی جوانه بزند."),
        EssayQuestion("چرا اثر هورمون‌های گیاهی معمولاً ترکیبی و وابسته به تعامل چند هورمون است؟", "هورمون‌های گیاهی به‌طور مستقل عمل نمی‌کنند؛ اثر نهایی یک پاسخ رشدی معمولاً حاصل تعادل و تعامل چند هورمون محرک (مانند اکسین، جیبرلین، سیتوکینین) و بازدارنده (مانند ABA) است، مشابه خواب دانه که نتیجه تعادل ABA و جیبرلین است."),
        EssayQuestion("فتوپریودیسم چیست؟", "فتوپریودیسم پاسخ گیاه به طول نسبی روز و شب است که در تنظیم زمان گلدهی و برخی فرایندهای فصلی دیگر گیاه نقش دارد."),
        EssayQuestion("سه گروه گیاهان را از نظر فتوپریودیسم نام برده و ویژگی هرکدام را بنویسید.", "گیاهان روز کوتاه: زمانی گل می‌دهند که طول شب از حد بحرانی بیشتر باشد (معمولاً پاییز).\nگیاهان روز بلند: زمانی گل می‌دهند که طول شب از حد بحرانی کمتر باشد (معمولاً بهار).\nگیاهان خنثی: گلدهی مستقل از طول روز و شب است."),
        EssayQuestion("فیتوکروم چیست و چه نقشی در گلدهی دارد؟", "فیتوکروم رنگدانه‌ای است که در برگ‌ها طول شب را حس می‌کند و بر اساس آن، علامت مولکولی لازم برای شروع یا توقف روند گلدهی را به سایر بخش‌های گیاه می‌فرستد."),
        EssayQuestion("گیاه چگونه در برابر تنش کم‌آبی از خود واکنش نشان می‌دهد؟", "در تنش کم‌آبی، غلظت آبسیزیک اسید در برگ افزایش می‌یابد که باعث بسته شدن روزنه‌های برگ می‌شود؛ بسته شدن روزنه‌ها میزان تبخیر و از دست رفتن آب گیاه را کاهش می‌دهد."),
        EssayQuestion("چرا برخی گیاهان در پاسخ به آسیب مکانیکی (مانند جویده شدن توسط حشرات) ترکیبات دفاعی تولید می‌کنند؟", "این ترکیبات شیمیایی دفاعی معمولاً برای گیاه‌خواران ناخوشایند یا سمی هستند و به‌عنوان یک سازوکار دفاعی، از آسیب بیشتر بافت گیاه توسط حشرات یا سایر گیاه‌خواران جلوگیری می‌کنند."),
        EssayQuestion("چرا استاتولیت‌ها (دانه‌های نشاسته‌ای سنگین) در حس گرانش توسط ریشه اهمیت دارند؟", "استاتولیت‌ها یاخته‌های ویژه‌ای در نوک ریشه هستند که به دلیل چگالی بالا، تحت تأثیر نیروی گرانش در پایین یاخته ته‌نشین می‌شوند؛ این ته‌نشینی به یاخته کمک می‌کند جهت گرانش را حس کرده و رشد ریشه را به سمت پایین هدایت کند.")
